// API Key authentication middleware
function authenticateApiKey(req, res, next) {
  // Extract API key from query parameter or header
  const apiKey = req.query.api_key || req.headers['x-api-key'];

  if (!apiKey) {
    debugLog('Authentication failed - No API key provided', {
      method: req.method,
      path: req.path,
      ip: req.ip
    });
    return res.status(401).json({
      error: 'Unauthorized',
      message: 'API key is required. Provide it via ?api_key=xxx query parameter or X-API-Key header.'
    });
  }

  if (!VALID_API_KEYS.has(apiKey)) {
    debugLog('Authentication failed - Invalid API key', {
      method: req.method,
      path: req.path,
      api_key: apiKey,
      ip: req.ip
    });
    return res.status(403).json({
      error: 'Forbidden',
      message: 'Invalid API key.'
    });
  }

  debugLog('Authentication successful', {
    method: req.method,
    path: req.path,
    api_key: apiKey,
    ip: req.ip
  });

  // Store API key for forwarding
  req.authenticatedApiKey = apiKey;
  next();
}

// Rate limiting simple implementation (per API key)
const rateLimitStore = new Map();
const RATE_LIMIT_WINDOW_MS = 60 * 1000; // 1 minute
const RATE_LIMIT_MAX_REQUESTS = 100;

function rateLimit(req, res, next) {
  const apiKey = req.authenticatedApiKey;
  const now = Date.now();

  if (!rateLimitStore.has(apiKey)) {
    rateLimitStore.set(apiKey, { count: 1, windowStart: now });
    return next();
  }

  const record = rateLimitStore.get(apiKey);

  if (now - record.windowStart > RATE_LIMIT_WINDOW_MS) {
    // Reset window
    record.count = 1;
    record.windowStart = now;
    return next();
  }

  record.count++;

  if (record.count > RATE_LIMIT_MAX_REQUESTS) {
    debugLog('Rate limit exceeded', {
      api_key: apiKey,
      count: record.count,
      path: req.path
    });
    return res.status(429).json({
      error: 'Too Many Requests',
      message: `Rate limit exceeded. Max ${RATE_LIMIT_MAX_REQUESTS} requests per minute.`,
      retryAfter: Math.ceil((record.windowStart + RATE_LIMIT_WINDOW_MS - now) / 1000)
    });
  }

  next();
}

