// Proxy middleware - forward requests to backend services
async function proxyRequest(req, res) {
  const originalPath = req.originalUrl.split('?')[0];
  const apiKey = req.authenticatedApiKey;

  // Find matching backend service
  let matchedPrefix = null;
  let matchedService = null;

  for (const [prefix, config] of Object.entries(BACKEND_SERVICES)) {
    if (originalPath.startsWith(prefix)) {
      matchedPrefix = prefix;
      matchedService = config;
      break;
    }
  }

  if (!matchedService) {
    debugLog('No matching backend service', {
      path: originalPath,
      api_key: apiKey
    });
    return res.status(404).json({
      error: 'Not Found',
      message: `No backend service found for path: ${originalPath}`
    });
  }

  // Build the target URL
  const remainingPath = originalPath.substring(matchedPrefix.length);
  const targetUrl = `${matchedService.target}${matchedPrefix}${remainingPath}`;

  // Build query parameters (exclude api_key from forwarded query)
  const forwardedQuery = { ...req.query };
  delete forwardedQuery.api_key;

  // Build headers to forward
  const forwardedHeaders = {
    'X-API-Key': apiKey,
    'X-Forwarded-For': req.ip,
    'X-Forwarded-Host': req.hostname,
    'X-Forwarded-Proto': req.protocol,
    'X-Gateway-Request-Id': generateRequestId(),
    'X-Original-URI': req.originalUrl
  };

  // Forward content-type if present
  if (req.headers['content-type']) {
    forwardedHeaders['Content-Type'] = req.headers['content-type'];
  }

  // Forward authorization header if present
  if (req.headers['authorization']) {
    forwardedHeaders['Authorization'] = req.headers['authorization'];
  }

  // Forward accept header
  if (req.headers['accept']) {
    forwardedHeaders['Accept'] = req.headers['accept'];
  }

  debugLog('Proxying request to backend', {
    method: req.method,
    originalPath,
    targetUrl,
    service: matchedService.name,
    api_key: apiKey,
    forwardedHeaders,
    forwardedQuery
  });

  const startTime = Date.now();

  try {
    const axiosConfig = {
      method: req.method.toLowerCase(),
      url: targetUrl,
      headers: forwardedHeaders,
      params: forwardedQuery,
      timeout: 30000,
      validateStatus: () => true // Don't throw on any status code
    };

    // Forward request body for methods that support it
    if (['POST', 'PUT', 'PATCH'].includes(req.method) && req.body) {
      axiosConfig.data = req.body;
    }

    const response = await axios(axiosConfig);
    const duration = Date.now() - startTime;

    debugLog('Backend response received', {
      method: req.method,
      targetUrl,
      service: matchedService.name,
      api_key: apiKey,
      statusCode: response.status,
      duration: `${duration}ms`,
      responseHeaders: response.headers
    });

    // Forward response headers from backend
    const headersToForward = [
      'content-type',
      'cache-control',
      'etag',
      'last-modified',
      'x-request-id'
    ];

    headersToForward.forEach(header => {
      if (response.headers[header]) {
        res.set(header, response.headers[header]);
      }
    });

    // Add gateway headers
    res.set('X-Gateway-Duration', `${duration}ms`);
    res.set('X-Gateway-Service', matchedService.name);

    return res.status(response.status).send(response.data);

  } catch (error) {
    const duration = Date.now() - startTime;

    debugLog('Backend request failed', {
      method: req.method,
      targetUrl,
      service: matchedService.name,
      api_key: apiKey,
      error: error.message,
      code: error.code,
      duration: `${duration}ms`
    });

    if (error.code === 'ECONNREFUSED') {
      return res.status(503).json({
        error: 'Service Unavailable',
        message: `Backend service "${matchedService.name}" is not available.`,
        service: matchedService.name
      });
    }

    if (error.code === 'ECONNABORTED' || error.code === 'ETIMEDOUT') {
      return res.status(504).json({
        error: 'Gateway Timeout',
        message: `Request to "${matchedService.name}" timed out.`,
        service: matchedService.name
      });
    }

    return res.status(502).json({
      error: 'Bad Gateway',
      message: `Error communicating with backend service "${matchedService.name}".`,
      service: matchedService.name
    });
  }
}

